//! encode-rknot — Resonance Knot encoder
//!
//! Two modes:
//!
//! 1. **Synthetic** (Phase 1) — generates uniform-0.5 dense tensors of
//!    Llama-shaped dims and runs them through the encoder pipeline. Used
//!    to measure file size and exercise the writer end-to-end with no
//!    external dependencies. See `RKNOT_RUST_CONTRACTS.md` Module 4.
//!
//!    ```text
//!    encode-rknot --synthetic --d 8192 --layers 80 \
//!      --intermediate-h 28672 --target-k 0.30 \
//!      --bits-qk 4 --bits-v 8 --bits-ffn 4 \
//!      --output /tmp/llama-70b-synthetic.rknot
//!    ```
//!
//! 2. **Input** (Phase 2) — reads a real dense `.knot` (Llama-70B,
//!    Gemma4-31B, …) via [`dense_reader::DenseKnotReader`], derives a
//!    real per-layer [`SpectralManifest`] from per-column L2 magnitudes
//!    on Q/K/V via [`manifest_real::manifest_from_weight_magnitudes`],
//!    encodes Q/K/V/FFN against that manifest, and writes the resulting
//!    `.rknot`. Optionally wraps each block payload with the codebook
//!    bonus from [`bitwise_fp48::fp48_pack`]. See
//!    `RKNOT_PHASE2_CONTRACTS.md` Module 4.
//!
//!    ```text
//!    encode-rknot --input <dense.knot> --output <out.rknot> \
//!      --target-k 0.30 --bits-qk 4 --bits-v 8 --bits-ffn 4 \
//!      [--layer-range 0..80] [--apply-fp48]
//!    ```
//!
//!    Phase 2 ASAP only supports fp16 / fp32 dense inputs. K-quant
//!    tensors return a clear error pointing at Phase 3.

use std::path::PathBuf;
use std::process::ExitCode;
use std::time::Instant;

use distributed_inference::rknot::bitwise_fp48::{fp48_bonus_ratio, fp48_pack, Fp48Packed};
use distributed_inference::rknot::dense_reader::{DenseKnotReader, DenseReadError, LayerTensors};
use distributed_inference::rknot::encoder::{encode_ffn_tensor, encode_tensor};
use distributed_inference::rknot::format::{
    cascade_ratio, dense_baseline_byte_size, ArchMeta, DenseTensor, QuantBlock, ResonanceKnotLayer,
    Rknot, SpectralManifest,
};
use distributed_inference::rknot::manifest::stub_strided_manifest;
use distributed_inference::rknot::manifest_real::{
    manifest_from_weight_magnitudes, standing_energy_fraction,
};
use distributed_inference::rknot::writer::{
    streaming_rknot_to_file, write_rknot_to_file, WriteError,
};

// ──────────────────────────────────────────────────────────────────────
// CLI
// ──────────────────────────────────────────────────────────────────────

/// Half-open layer range `[start, end)` — mirrors Rust `Range<u32>`.
/// Stored separately from the rest of `Args` because `--input` mode
/// resolves the upper bound from the dense knot's `KnotConfig` if the
/// flag is absent.
#[derive(Debug, Clone, Copy)]
struct LayerRange {
    start: u32,
    end: u32,
}

#[derive(Debug)]
struct Args {
    synthetic: bool,
    input: Option<PathBuf>,
    d: u32,
    layers: u32,
    intermediate_h: u32,
    target_k: f32,
    bits_qk: u8,
    bits_v: u8,
    bits_ffn: u8,
    layer_range: Option<LayerRange>,
    apply_fp48: bool,
    /// Optional path to a `.pca` sidecar (PCAB magic) emitted by
    /// `standing-wave-pca`. When present, per-layer manifests are
    /// derived from the calibrated PCA basis instead of the magnitude
    /// heuristic — empirically 50–100× lower KL at the same coverage
    /// (per the standing-wave handoff).
    input_pca: Option<PathBuf>,
    output: Option<PathBuf>,
}

impl Default for Args {
    fn default() -> Self {
        // Defaults match Llama-70B per RKNOT_RUST_CONTRACTS.md Module 4.
        Args {
            synthetic: false,
            input: None,
            d: 8192,
            layers: 80,
            intermediate_h: 28672,
            target_k: 0.30,
            bits_qk: 4,
            bits_v: 8,
            bits_ffn: 4,
            layer_range: None,
            apply_fp48: false,
            input_pca: None,
            output: None,
        }
    }
}

fn print_usage() {
    eprintln!(
        "encode-rknot — Resonance Knot encoder

USAGE:
  encode-rknot --synthetic --output <path> [synthetic-flags]
  encode-rknot --input <dense.knot> --output <path> [input-flags]

MODE FLAGS (mutually exclusive):
  --synthetic                Synthesize dense tensors (Phase 1 / benchmark mode)
  --input <path>             Read a real dense .knot (Phase 2)

SHARED FLAGS:
  --target-k <f32>           Standing-set coverage (default 0.30)
  --bits-qk <u8>             Q/K bits per entry (default 4)
  --bits-v <u8>              V bits per entry (default 8)
  --bits-ffn <u8>            FFN bits per entry (default 4)
  --output <path>            Output .rknot file (required)
  -h, --help                 Print this message

SYNTHETIC-ONLY FLAGS:
  --d <u32>                  Hidden dim (default 8192 = Llama-70B)
  --layers <u32>             Layer count (default 80 = Llama-70B)
  --intermediate-h <u32>     FFN intermediate dim (default 28672)

INPUT-ONLY FLAGS:
  --layer-range <s>..<e>     Half-open layer range; default = all layers
  --apply-fp48               Wrap each block payload through fp48_pack
                             for the codebook bonus (Phase 3 will round-trip)
  --input-pca <path>         Read a .pca (PCAB) sidecar from `standing-wave-pca`
                             and derive per-layer manifests from the calibrated
                             principal components instead of weight magnitudes.
                             Layers absent from the sidecar fall back to the
                             magnitude heuristic. 50–100× lower KL at same
                             coverage on the empirical Qwen 0.5B handoff."
    );
}

fn parse_layer_range(s: &str) -> Result<LayerRange, String> {
    // Accept both `start..end` (Rust style) and `start-end` for
    // shell-friendliness. Reject everything else.
    let sep = if s.contains("..") {
        ".."
    } else if s.contains('-') {
        "-"
    } else {
        return Err(format!("--layer-range: expected `start..end`, got `{s}`"));
    };
    let parts: Vec<&str> = s.split(sep).collect();
    if parts.len() != 2 {
        return Err(format!("--layer-range: expected `start..end`, got `{s}`"));
    }
    let start: u32 = parts[0]
        .parse()
        .map_err(|e| format!("--layer-range start: {e}"))?;
    let end: u32 = parts[1]
        .parse()
        .map_err(|e| format!("--layer-range end: {e}"))?;
    if end < start {
        return Err(format!("--layer-range: end {end} must be >= start {start}"));
    }
    Ok(LayerRange { start, end })
}

fn parse_args() -> Result<Args, String> {
    let mut args = Args::default();
    let mut iter = std::env::args().skip(1);
    while let Some(flag) = iter.next() {
        match flag.as_str() {
            "--synthetic" => args.synthetic = true,
            "--input" => {
                let val = iter
                    .next()
                    .ok_or_else(|| "--input requires a path".to_string())?;
                args.input = Some(PathBuf::from(val));
            }
            "--d" => {
                args.d = iter
                    .next()
                    .ok_or_else(|| "--d requires a value".to_string())?
                    .parse()
                    .map_err(|e| format!("--d: {e}"))?;
            }
            "--layers" => {
                args.layers = iter
                    .next()
                    .ok_or_else(|| "--layers requires a value".to_string())?
                    .parse()
                    .map_err(|e| format!("--layers: {e}"))?;
            }
            "--intermediate-h" => {
                args.intermediate_h = iter
                    .next()
                    .ok_or_else(|| "--intermediate-h requires a value".to_string())?
                    .parse()
                    .map_err(|e| format!("--intermediate-h: {e}"))?;
            }
            "--target-k" => {
                args.target_k = iter
                    .next()
                    .ok_or_else(|| "--target-k requires a value".to_string())?
                    .parse()
                    .map_err(|e| format!("--target-k: {e}"))?;
            }
            "--bits-qk" => {
                args.bits_qk = iter
                    .next()
                    .ok_or_else(|| "--bits-qk requires a value".to_string())?
                    .parse()
                    .map_err(|e| format!("--bits-qk: {e}"))?;
            }
            "--bits-v" => {
                args.bits_v = iter
                    .next()
                    .ok_or_else(|| "--bits-v requires a value".to_string())?
                    .parse()
                    .map_err(|e| format!("--bits-v: {e}"))?;
            }
            "--bits-ffn" => {
                args.bits_ffn = iter
                    .next()
                    .ok_or_else(|| "--bits-ffn requires a value".to_string())?
                    .parse()
                    .map_err(|e| format!("--bits-ffn: {e}"))?;
            }
            "--layer-range" => {
                let val = iter
                    .next()
                    .ok_or_else(|| "--layer-range requires a value".to_string())?;
                args.layer_range = Some(parse_layer_range(&val)?);
            }
            "--apply-fp48" => args.apply_fp48 = true,
            "--input-pca" => {
                let val = iter
                    .next()
                    .ok_or_else(|| "--input-pca requires a path".to_string())?;
                args.input_pca = Some(PathBuf::from(val));
            }
            "--output" => {
                let val = iter
                    .next()
                    .ok_or_else(|| "--output requires a path".to_string())?;
                args.output = Some(PathBuf::from(val));
            }
            "-h" | "--help" => {
                print_usage();
                std::process::exit(0);
            }
            other => return Err(format!("unknown argument: {other}")),
        }
    }
    if args.synthetic && args.input.is_some() {
        return Err("--synthetic and --input are mutually exclusive".to_string());
    }
    if !args.synthetic && args.input.is_none() {
        return Err("must pass exactly one of --synthetic or --input <path>".to_string());
    }
    if args.output.is_none() {
        return Err("--output <path> is required".to_string());
    }
    if args.apply_fp48 && args.synthetic {
        // Synthetic mode is for measuring the raw compression-ratio
        // floor; mixing in fp48 would double-count the bonus.
        return Err("--apply-fp48 only valid with --input mode".to_string());
    }
    if args.input_pca.is_some() && args.synthetic {
        return Err("--input-pca only valid with --input mode".to_string());
    }
    Ok(args)
}

// ──────────────────────────────────────────────────────────────────────
// Synthetic dense tensor builders
//
// The synthetic mode doesn't read a real .knot — it allocates uniform-0.5
// dense tensors of the right shape so the writer pipeline can be exercised
// end to end and we can measure on-disk byte size.
// ──────────────────────────────────────────────────────────────────────

fn synthetic_square(d: u32) -> DenseTensor {
    let n = d as usize;
    DenseTensor {
        rows: d,
        cols: d,
        data: vec![0.5_f32; n * n],
    }
}

fn synthetic_rect(rows: u32, cols: u32) -> DenseTensor {
    let n = rows as usize * cols as usize;
    DenseTensor {
        rows,
        cols,
        data: vec![0.5_f32; n],
    }
}

// ──────────────────────────────────────────────────────────────────────
// Per-block timing helper
// ──────────────────────────────────────────────────────────────────────

#[derive(Default, Clone, Copy)]
struct BlockTimings {
    q_ms: f64,
    k_ms: f64,
    v_ms: f64,
    ffn_ms: f64,
}

impl BlockTimings {
    fn add(&mut self, other: &BlockTimings) {
        self.q_ms += other.q_ms;
        self.k_ms += other.k_ms;
        self.v_ms += other.v_ms;
        self.ffn_ms += other.ffn_ms;
    }

    fn total_ms(&self) -> f64 {
        self.q_ms + self.k_ms + self.v_ms + self.ffn_ms
    }
}

// ──────────────────────────────────────────────────────────────────────
// Synthetic encode pipeline
// ──────────────────────────────────────────────────────────────────────

fn build_synthetic_layer(
    layer_idx: u32,
    d: u32,
    intermediate_h: u32,
    target_k: f32,
    bits_qk: u8,
    bits_v: u8,
    bits_ffn: u8,
    timings: &mut BlockTimings,
) -> ResonanceKnotLayer {
    let manifest = stub_strided_manifest(d, target_k);

    // Synthesize once and reuse for Q/K/V (uniform-0.5 means the
    // tensors are identical anyway; allocating one and re-reading it
    // through the encoder mirrors the per-block-encode access pattern
    // without tripling memory cost on Llama-70B-shaped runs).
    let qkv_tensor = synthetic_square(d);

    let t = Instant::now();
    let q_block = encode_tensor(&qkv_tensor, &manifest, bits_qk);
    timings.q_ms = t.elapsed().as_secs_f64() * 1e3;

    let t = Instant::now();
    let k_block = encode_tensor(&qkv_tensor, &manifest, bits_qk);
    timings.k_ms = t.elapsed().as_secs_f64() * 1e3;

    let t = Instant::now();
    let v_block = encode_tensor(&qkv_tensor, &manifest, bits_v);
    timings.v_ms = t.elapsed().as_secs_f64() * 1e3;

    // FFN: k × intermediate_h. Allocated separately so we don't pay
    // d² × 4 + d × h × 4 simultaneously.
    drop(qkv_tensor);
    let ffn_tensor = synthetic_rect(d, intermediate_h);
    let t = Instant::now();
    let ffn_block = encode_ffn_tensor(&ffn_tensor, &manifest, intermediate_h, bits_ffn);
    timings.ffn_ms = t.elapsed().as_secs_f64() * 1e3;

    ResonanceKnotLayer {
        layer_idx,
        manifest,
        q_block,
        k_block,
        v_block,
        ffn_block,
    }
}

fn synthetic_arch_meta(args: &Args) -> ArchMeta {
    // Synthetic ArchMeta — these fields exist to round-trip the
    // dense-knot KnotConfig surface. Llama-70B-style defaults derived
    // from the CLI dims so the loader can still reason about head
    // counts and rope params without a real GGUF.
    let head_dim: u32 = 128;
    let num_heads = args.d / head_dim;
    let num_kv_heads = (num_heads / 8).max(1); // GQA assumption
    ArchMeta {
        arch: "llama".to_string(),
        hidden_dim: args.d,
        num_layers: args.layers,
        num_heads,
        num_kv_heads,
        head_dim,
        intermediate_size: args.intermediate_h,
        vocab_size: 128_256, // Llama-3 vocab; placeholder for synthetic runs
        rms_norm_eps: 1e-5,
        rope_theta: 500_000.0,
    }
}

// ──────────────────────────────────────────────────────────────────────
// Input encode pipeline (Phase 2)
// ──────────────────────────────────────────────────────────────────────

/// Per-layer measurement bucket carried into the summary table. Keeps
/// dense-vs-encoded sizes, per-block fp48 bonus, and the energy
/// fractions captured by the real manifest on each tensor.
///
/// `layer_idx` and `timings` are stashed for the Phase-3 verify-rknot
/// per-layer table even though the current summary aggregates without
/// them; `#[allow(dead_code)]` keeps that contract surface explicit
/// rather than silently dropping the fields.
#[derive(Clone, Default)]
#[allow(dead_code)]
struct LayerStats {
    layer_idx: u32,
    dense_bytes: u64,
    encoded_bytes: u64,
    fp48_bytes: u64, // encoded payload bytes after fp48 pack (== encoded_bytes when not applied)
    energy_q: f32,
    energy_k: f32,
    energy_v: f32,
    energy_ffn: f32,
    timings: BlockTimings,
}

/// Sum of `rows × cols × 4` over every dense tensor we read for one
/// layer. Used as the per-layer dense baseline for the cascade ratio
/// (fp32 source bytes — what the dense `.knot` would weigh if it were
/// stored as flat fp32). The encoded `.rknot` is then reported against
/// this baseline.
fn dense_layer_bytes(blocks: &LayerTensors) -> u64 {
    let bytes = |t: &DenseTensor| -> u64 { t.rows as u64 * t.cols as u64 * 4 };
    bytes(&blocks.q) + bytes(&blocks.k) + bytes(&blocks.v) + bytes(&blocks.ffn)
}

/// Wrap a `QuantBlock` payload through `fp48_pack` and replace the
/// payload with the JSON-serialized `Fp48Packed`. The decoder side
/// will unpack — round-trip lands in Phase 3 (see contract). For
/// Phase 2 we just record the post-pack byte size for the summary.
fn wrap_with_fp48(mut block: QuantBlock) -> (QuantBlock, Fp48Packed) {
    let packed = fp48_pack(&block.payload);
    let serialized = serde_json::to_vec(&serde_json::json!({
        "codebook": packed.codebook.iter().map(|w| w.to_vec()).collect::<Vec<_>>(),
        "indices": packed.indices,
        "literals": packed.literals,
        "original_byte_len": packed.original_byte_len,
    }))
    .unwrap_or_default();
    block.payload = serialized;
    (block, packed)
}

#[allow(clippy::too_many_arguments)]
fn build_input_layer(
    layer_idx: u32,
    blocks: &LayerTensors,
    target_k: f32,
    bits_qk: u8,
    bits_v: u8,
    bits_ffn: u8,
    apply_fp48: bool,
    pca: Option<&mut distributed_inference::rknot::manifest_from_pca::PcaBasis>,
    timings: &mut BlockTimings,
) -> (
    ResonanceKnotLayer,
    LayerStats,
    SpectralManifest,
    ManifestSource,
) {
    // Synergy: prefer the calibrated PCA basis if a sidecar is loaded
    // and this layer has a fitted basis. Falls back to the magnitude
    // heuristic for any layer absent from the PCAB.
    let (manifest, source) = match pca {
        Some(p) => {
            let num_layers = p.num_layers;
            let hidden_dim = p.hidden_dim;
            match p.take_layer(layer_idx as usize) {
                Some(info) => {
                    let info_ref = (info.0, info.1.as_slice(), info.2.as_slice());
                    // Outlier-preservation pass on the calibrated PCA path:
                    // the same ±72 / ±92 elements that broke the magnitude
                    // path (cloud probe `e839d9dd`) are present regardless
                    // of which scoring pass is used. Hand the layer's
                    // Q/K/V/FFN tensors through so columns containing
                    // extreme weights survive even when their PCA score
                    // would have been beaten.
                    let outlier_tensors: [&DenseTensor; 4] =
                        [&blocks.q, &blocks.k, &blocks.v, &blocks.ffn];
                    match distributed_inference::rknot::manifest_from_pca::manifest_for_layer_with_outliers(
                        layer_idx as usize,
                        num_layers,
                        hidden_dim,
                        info_ref,
                        target_k,
                        Some(&outlier_tensors),
                    ) {
                        Ok(m) => (m, ManifestSource::Pca),
                        Err(_) => (
                            manifest_from_weight_magnitudes(
                                &blocks.q, &blocks.k, &blocks.v, target_k,
                            ),
                            ManifestSource::Magnitude,
                        ),
                    }
                }
                None => (
                    manifest_from_weight_magnitudes(&blocks.q, &blocks.k, &blocks.v, target_k),
                    ManifestSource::Magnitude,
                ),
            }
        }
        None => (
            manifest_from_weight_magnitudes(&blocks.q, &blocks.k, &blocks.v, target_k),
            ManifestSource::Magnitude,
        ),
    };

    // Per-tensor energy fractions — sanity check that the magnitude-
    // derived manifest actually covered the load-bearing columns.
    let energy_q = standing_energy_fraction(&blocks.q, &manifest);
    let energy_k = standing_energy_fraction(&blocks.k, &manifest);
    let energy_v = standing_energy_fraction(&blocks.v, &manifest);
    let energy_ffn = standing_energy_fraction(&blocks.ffn, &manifest);

    let q_dim = blocks.q.cols;
    let t = Instant::now();
    let q_block = encode_ffn_tensor(&blocks.q, &manifest, q_dim, bits_qk);
    timings.q_ms = t.elapsed().as_secs_f64() * 1e3;

    // K and V are rectangular [hidden, kv_dim] under GQA — kv_dim < hidden
    // (e.g. Llama-70B has 8 KV heads × 128 head_dim = 1024 vs hidden 8192).
    // encode_tensor assumes a square hidden×hidden matrix and reads
    // tensor.get(standing_row, standing_col) where standing_col can index up
    // to hidden_dim. DenseTensor::get returns 0.0 for out-of-range, so any
    // standing_col >= kv_dim silently encodes as zero — ~87% of K/V values
    // for Llama-70B. The per-tensor energy metric reads the same way and
    // reports K=V=1.000 because zero round-trips perfectly.
    //
    // Use encode_ffn_tensor for K and V instead — it restricts only the
    // ROW axis to standing_indices and takes the column axis in full,
    // matching the rectangular FFN shape pattern.
    let kv_dim = blocks.k.cols;
    let t = Instant::now();
    let k_block = encode_ffn_tensor(&blocks.k, &manifest, kv_dim, bits_qk);
    timings.k_ms = t.elapsed().as_secs_f64() * 1e3;

    let t = Instant::now();
    let v_block = encode_ffn_tensor(&blocks.v, &manifest, kv_dim, bits_v);
    timings.v_ms = t.elapsed().as_secs_f64() * 1e3;

    let ffn_h = blocks.ffn.cols;
    let t = Instant::now();
    let ffn_block = encode_ffn_tensor(&blocks.ffn, &manifest, ffn_h, bits_ffn);
    timings.ffn_ms = t.elapsed().as_secs_f64() * 1e3;

    // Pre-fp48 encoded payload bytes (what the .rknot would weigh
    // without the codebook bonus).
    let encoded_bytes = q_block.payload.len() as u64
        + k_block.payload.len() as u64
        + v_block.payload.len() as u64
        + ffn_block.payload.len() as u64;

    let (q_block, k_block, v_block, ffn_block, fp48_bytes) = if apply_fp48 {
        let (q_b, _q_p) = wrap_with_fp48(q_block);
        let (k_b, _k_p) = wrap_with_fp48(k_block);
        let (v_b, _v_p) = wrap_with_fp48(v_block);
        let (f_b, _f_p) = wrap_with_fp48(ffn_block);
        let post = q_b.payload.len() as u64
            + k_b.payload.len() as u64
            + v_b.payload.len() as u64
            + f_b.payload.len() as u64;
        (q_b, k_b, v_b, f_b, post)
    } else {
        (q_block, k_block, v_block, ffn_block, encoded_bytes)
    };

    let stats = LayerStats {
        layer_idx,
        dense_bytes: dense_layer_bytes(blocks),
        encoded_bytes,
        fp48_bytes,
        energy_q,
        energy_k,
        energy_v,
        energy_ffn,
        timings: *timings,
    };

    let manifest_clone = manifest.clone();
    let layer = ResonanceKnotLayer {
        layer_idx,
        manifest,
        q_block,
        k_block,
        v_block,
        ffn_block,
    };
    (layer, stats, manifest_clone, source)
}

/// Where a layer's manifest came from. Reported in the per-layer
/// summary so the operator can see whether the PCA sidecar covered
/// every layer or whether some fell back to the magnitude heuristic.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum ManifestSource {
    Pca,
    Magnitude,
}

impl ManifestSource {
    fn tag(self) -> &'static str {
        match self {
            ManifestSource::Pca => "pca",
            ManifestSource::Magnitude => "mag",
        }
    }
}

fn input_arch_meta(reader: &DenseKnotReader) -> ArchMeta {
    // Lift the dense knot's KnotConfig into our ArchMeta surface.
    // Field-by-field cast u32/f32 because KnotConfig stores everything
    // as `usize` (host width) and our format wire is u32-bounded.
    let cfg = &reader.config;
    ArchMeta {
        arch: cfg.arch.clone(),
        hidden_dim: cfg.hidden_dim as u32,
        num_layers: cfg.num_layers as u32,
        num_heads: cfg.num_heads as u32,
        num_kv_heads: cfg.num_kv_heads as u32,
        head_dim: cfg.head_dim as u32,
        intermediate_size: cfg.intermediate_size as u32,
        vocab_size: cfg.vocab_size as u32,
        rms_norm_eps: cfg.rms_norm_eps,
        rope_theta: cfg.rope_theta,
    }
}

// ──────────────────────────────────────────────────────────────────────
// main
// ──────────────────────────────────────────────────────────────────────

fn main() -> ExitCode {
    let args = match parse_args() {
        Ok(a) => a,
        Err(e) => {
            eprintln!("encode-rknot: {e}");
            print_usage();
            return ExitCode::from(2);
        }
    };

    if args.synthetic {
        run_synthetic(&args)
    } else {
        run_input(&args)
    }
}

// ──────────────────────────────────────────────────────────────────────
// Synthetic driver — preserves the Phase 1 behaviour byte-for-byte.
// ──────────────────────────────────────────────────────────────────────

fn run_synthetic(args: &Args) -> ExitCode {
    let output = args.output.clone().expect("output validated above");

    eprintln!(
        "encode-rknot: synthetic Llama-shaped run \
         d={} layers={} h={} target_k={} bits_qk={} bits_v={} bits_ffn={}",
        args.d,
        args.layers,
        args.intermediate_h,
        args.target_k,
        args.bits_qk,
        args.bits_v,
        args.bits_ffn,
    );

    let arch_meta = synthetic_arch_meta(args);
    let mut layers: Vec<ResonanceKnotLayer> = Vec::with_capacity(args.layers as usize);
    let mut total_timings = BlockTimings::default();
    let encode_start = Instant::now();
    for layer_idx in 0..args.layers {
        let mut t = BlockTimings::default();
        let layer = build_synthetic_layer(
            layer_idx,
            args.d,
            args.intermediate_h,
            args.target_k,
            args.bits_qk,
            args.bits_v,
            args.bits_ffn,
            &mut t,
        );
        eprintln!(
            "  layer {:>3}/{}: q={:.1}ms k={:.1}ms v={:.1}ms ffn={:.1}ms (total {:.1}ms)",
            layer_idx + 1,
            args.layers,
            t.q_ms,
            t.k_ms,
            t.v_ms,
            t.ffn_ms,
            t.total_ms(),
        );
        total_timings.add(&t);
        layers.push(layer);
    }
    let encode_elapsed = encode_start.elapsed();

    let knot = Rknot {
        arch_meta,
        layers,
        encoder_version: "rknot-encoder/0.1.0".to_string(),
        calibration_probe: Some("synthetic-uniform-0.5".to_string()),
        saturation_maps: None,
    };

    let write_start = Instant::now();
    let bytes_written = match write_rknot_to_file(&output, &knot) {
        Ok(n) => n,
        Err(e) => {
            eprintln!("encode-rknot: write failed: {e:?}");
            return ExitCode::from(1);
        }
    };
    let write_elapsed = write_start.elapsed();

    // Reporting per Module 4 contract: dense baseline, actual rknot size,
    // compression ratio, per-block timing, cascade-ratio prediction.
    let baseline = dense_baseline_byte_size(args.d, args.intermediate_h);
    let baseline_total = baseline.saturating_mul(args.layers as u64);
    let ratio = if bytes_written == 0 {
        0.0
    } else {
        baseline_total as f64 / bytes_written as f64
    };
    // Cascade-ratio prediction uses k from a single layer's manifest.
    let predicted_k = ((args.d as f32) * args.target_k.clamp(0.0, 1.0)).ceil() as u32;
    let predicted_cascade = cascade_ratio(args.d, predicted_k);

    eprintln!();
    eprintln!("── encode-rknot summary (synthetic) ──");
    eprintln!(
        "dense baseline (per layer):  {:>14} bytes  ({:.2} GiB)",
        baseline,
        baseline as f64 / (1024.0 * 1024.0 * 1024.0)
    );
    eprintln!(
        "dense baseline (all layers): {:>14} bytes  ({:.2} GiB)",
        baseline_total,
        baseline_total as f64 / (1024.0 * 1024.0 * 1024.0)
    );
    eprintln!(
        "actual .rknot file:          {:>14} bytes  ({:.2} MiB)",
        bytes_written,
        bytes_written as f64 / (1024.0 * 1024.0)
    );
    eprintln!("compression ratio:           {:>14.2}×", ratio);
    eprintln!(
        "cascade-ratio prediction:    {:>14}× (d={} k={} target={:.2})",
        predicted_cascade, args.d, predicted_k, args.target_k
    );
    eprintln!(
        "encode time total:           {:>14.2} ms  (Q {:.1} / K {:.1} / V {:.1} / FFN {:.1})",
        encode_elapsed.as_secs_f64() * 1e3,
        total_timings.q_ms,
        total_timings.k_ms,
        total_timings.v_ms,
        total_timings.ffn_ms,
    );
    eprintln!(
        "write time:                  {:>14.2} ms",
        write_elapsed.as_secs_f64() * 1e3
    );
    eprintln!("output: {}", output.display());

    ExitCode::SUCCESS
}

// ──────────────────────────────────────────────────────────────────────
// Input driver — Phase 2 real-knot pipeline.
// ──────────────────────────────────────────────────────────────────────

fn run_input(args: &Args) -> ExitCode {
    let input = args.input.clone().expect("input validated above");
    let output = args.output.clone().expect("output validated above");

    // Source-knot bytes and metadata for the summary line. We tolerate
    // a metadata read failure here because `DenseKnotReader::open`
    // below will produce a more actionable error if the file is bad.
    let dense_input_bytes = std::fs::metadata(&input).map(|m| m.len()).unwrap_or(0);

    let mut reader = match DenseKnotReader::open(&input) {
        Ok(r) => r,
        Err(e) => {
            eprintln!(
                "encode-rknot: failed to open dense knot {}: {e}",
                input.display()
            );
            return ExitCode::from(1);
        }
    };

    let arch_meta = input_arch_meta(&reader);
    let model_layers = arch_meta.num_layers;
    let layer_range = args.layer_range.unwrap_or(LayerRange {
        start: 0,
        end: model_layers,
    });
    if layer_range.end > model_layers {
        eprintln!(
            "encode-rknot: --layer-range end {} exceeds model.num_layers {}",
            layer_range.end, model_layers
        );
        return ExitCode::from(2);
    }

    eprintln!(
        "encode-rknot: input mode arch={} d={} layers={} h={} \
         range={}..{} target_k={} bits_qk={} bits_v={} bits_ffn={} fp48={}",
        arch_meta.arch,
        arch_meta.hidden_dim,
        arch_meta.num_layers,
        arch_meta.intermediate_size,
        layer_range.start,
        layer_range.end,
        args.target_k,
        args.bits_qk,
        args.bits_v,
        args.bits_ffn,
        args.apply_fp48,
    );
    eprintln!(
        "  source dense .knot: {} ({:.2} GiB, {} tensors)",
        input.display(),
        dense_input_bytes as f64 / (1024.0 * 1024.0 * 1024.0),
        reader.tensors.len(),
    );

    // Optional PCA sidecar (synergy with the standing-wave-pca fitter).
    // Loaded once; consulted per-layer; falls back to magnitude when a
    // layer has no fitted basis.
    let mut pca = match &args.input_pca {
        Some(path) => {
            let path_str = path.to_string_lossy().into_owned();
            match distributed_inference::rknot::manifest_from_pca::PcaBasis::open(&path_str) {
                Ok(p) => {
                    let fitted: Vec<usize> = p.fitted_layers().map(|(l, _)| l).collect();
                    eprintln!(
                        "  PCA sidecar: {} ({} fitted layers: {:?})",
                        path_str,
                        fitted.len(),
                        fitted
                    );
                    Some(p)
                }
                Err(e) => {
                    eprintln!("encode-rknot: failed to load --input-pca: {}", e);
                    return ExitCode::from(4);
                }
            }
        }
        None => None,
    };

    // Streaming writer: open the output file, write magic + reserved
    // header region, then append each layer's blocks to disk inside
    // the encode loop. The writer keeps at most one layer's worth of
    // RknotLayerRef metadata in memory (offsets + manifest, NOT
    // block payloads) — peak RAM drops from ~325 MiB × 80 layers
    // (~26 GiB, OOM at L73 on 32 GiB E2_HIGHCPU_32) to ~325 MiB ×
    // 1 layer for the conservative Llama-70B profile (k=0.50 b6/8/6).
    //
    // Probe-label trade-off: the streaming header is locked at
    // `start()` time, but the historical exact label depends on
    // per-layer pca/mag tallies that aren't known until after the
    // loop. We pass a *predicted* label up front based on whether
    // `--input-pca` was set, log a warning at finalize if the
    // post-loop label differs, and keep the loop's exact label in
    // stderr-only forensics. A secondary writer-side
    // `update_probe()` seek-rewrite is possible if a downstream
    // consumer ever needs the exact text in the header.
    let probe_label_predicted = match &args.input_pca {
        Some(p) => format!(
            "pcab-coordinate-topk (sidecar {})",
            p.file_name()
                .map(|s| s.to_string_lossy().into_owned())
                .unwrap_or_default()
        ),
        None => format!(
            "weight-magnitude-l2 from {}",
            input
                .file_name()
                .map(|s| s.to_string_lossy().into_owned())
                .unwrap_or_default()
        ),
    };
    let encoder_version = "rknot-encoder/0.3.0".to_string();

    let mut writer = match streaming_rknot_to_file(
        &output,
        arch_meta.clone(),
        encoder_version.clone(),
        Some(probe_label_predicted.clone()),
    ) {
        Ok(w) => w,
        Err(e) => {
            eprintln!("encode-rknot: streaming writer open failed: {e:?}");
            return ExitCode::from(1);
        }
    };

    let mut all_stats: Vec<LayerStats> = Vec::new();
    let mut total_timings = BlockTimings::default();
    let mut pca_layer_count = 0u32;
    let mut mag_layer_count = 0u32;

    let encode_start = Instant::now();
    let mut total_write_ms: f64 = 0.0;
    for layer_idx in layer_range.start..layer_range.end {
        let blocks = match reader.load_layer_blocks(layer_idx) {
            Ok(b) => b,
            Err(e) => {
                if let DenseReadError::UnsupportedQuantType(qt) = &e {
                    eprintln!(
                        "encode-rknot: tensor at layer {} uses quant type {} — \
                         Phase 2 supports fp16/fp32 input only. K-quant dequant \
                         lands in Phase 3. Use a fp16 .knot for now or wait for Phase 3.",
                        layer_idx, qt
                    );
                    return ExitCode::from(3);
                }
                eprintln!(
                    "encode-rknot: failed to load layer {} blocks: {e}",
                    layer_idx
                );
                return ExitCode::from(1);
            }
        };

        let mut t = BlockTimings::default();
        let (layer, stats, manifest, source) = build_input_layer(
            layer_idx,
            &blocks,
            args.target_k,
            args.bits_qk,
            args.bits_v,
            args.bits_ffn,
            args.apply_fp48,
            pca.as_mut(),
            &mut t,
        );
        match source {
            ManifestSource::Pca => pca_layer_count += 1,
            ManifestSource::Magnitude => mag_layer_count += 1,
        }

        eprintln!(
            "  layer {:>3}: src={} dense={:>10}B encoded={:>10}B (fp48={:>10}B) \
             k={:>4}/{} energy Q={:.3} K={:.3} V={:.3} FFN={:.3} \
             [Q {:.0}ms/K {:.0}ms/V {:.0}ms/FFN {:.0}ms]",
            layer_idx,
            source.tag(),
            stats.dense_bytes,
            stats.encoded_bytes,
            stats.fp48_bytes,
            manifest.k,
            manifest.d,
            stats.energy_q,
            stats.energy_k,
            stats.energy_v,
            stats.energy_ffn,
            t.q_ms,
            t.k_ms,
            t.v_ms,
            t.ffn_ms,
        );
        total_timings.add(&t);
        all_stats.push(stats);
        // Stream-write this layer to disk and free its block payloads
        // before we read the next layer from the dense knot. This is
        // the OOM fix: prior code accumulated `layers.push(layer)`
        // and built a single `Rknot` of ~26 GiB before writing, OOM-
        // ing at L73 on Cloud Build's 32 GiB E2_HIGHCPU_32. Now
        // memory floor is one layer (~325 MiB at conservative
        // profile).
        let write_start = Instant::now();
        if let Err(e) = writer.append_layer(layer) {
            match e {
                WriteError::MalformedManifest { layer_idx } => {
                    eprintln!("encode-rknot: malformed manifest at layer {}", layer_idx);
                }
                other => {
                    eprintln!("encode-rknot: streaming append failed: {other:?}");
                }
            }
            return ExitCode::from(1);
        }
        total_write_ms += write_start.elapsed().as_secs_f64() * 1e3;
    }
    let encode_elapsed = encode_start.elapsed();

    // Note: predicted probe label was passed at writer.start. The
    // historical exact label (which counts per-source layer
    // attribution) is logged here for the operator but doesn't make
    // it into the on-disk header — switching to the streaming
    // writer locks the probe label at start time. Keep this for the
    // forensics in the encode summary; if exact probe text in the
    // file becomes load-bearing for a downstream consumer we can
    // either (a) do a small writer.update_probe() seek-rewrite or
    // (b) require a pre-pass to compute it.
    let probe_label_actual = match (pca_layer_count, mag_layer_count, &args.input_pca) {
        (n, 0, Some(p)) => format!(
            "pcab-coordinate-topk × {} layers from {}",
            n,
            p.file_name()
                .map(|s| s.to_string_lossy().into_owned())
                .unwrap_or_default()
        ),
        (n, m, Some(p)) if n > 0 => format!(
            "pcab-coordinate-topk × {} + magnitude-l2 × {} (sidecar {})",
            n,
            m,
            p.file_name()
                .map(|s| s.to_string_lossy().into_owned())
                .unwrap_or_default()
        ),
        _ => format!(
            "weight-magnitude-l2 from {}",
            input
                .file_name()
                .map(|s| s.to_string_lossy().into_owned())
                .unwrap_or_default()
        ),
    };
    if probe_label_actual != probe_label_predicted {
        eprintln!(
            "encode-rknot: NOTE probe label differs at finalize \
             (header has predicted='{probe_label_predicted}', actual='{probe_label_actual}')"
        );
    }

    let write_start = Instant::now();
    let bytes_written = match writer.finalize() {
        Ok(n) => n,
        Err(e) => {
            eprintln!("encode-rknot: write finalize failed: {e:?}");
            return ExitCode::from(1);
        }
    };
    let write_elapsed = write_start.elapsed();
    eprintln!(
        "encode-rknot: per-layer streaming write totaled {:.1} ms; finalize {:.1} ms",
        total_write_ms,
        write_elapsed.as_secs_f64() * 1e3
    );

    print_input_summary(
        args,
        &all_stats,
        dense_input_bytes,
        bytes_written,
        encode_elapsed.as_secs_f64() * 1e3,
        write_elapsed.as_secs_f64() * 1e3,
        &total_timings,
        &output,
    );

    ExitCode::SUCCESS
}

#[allow(clippy::too_many_arguments)]
fn print_input_summary(
    args: &Args,
    stats: &[LayerStats],
    dense_input_bytes: u64,
    rknot_bytes: u64,
    encode_ms: f64,
    write_ms: f64,
    total_timings: &BlockTimings,
    output: &PathBuf,
) {
    let dense_total: u64 = stats.iter().map(|s| s.dense_bytes).sum();
    let encoded_total: u64 = stats.iter().map(|s| s.encoded_bytes).sum();
    let fp48_total: u64 = stats.iter().map(|s| s.fp48_bytes).sum();

    let cascade_ratio = if rknot_bytes == 0 {
        0.0
    } else {
        dense_input_bytes as f64 / rknot_bytes as f64
    };
    let payload_ratio = if encoded_total == 0 {
        0.0
    } else {
        dense_total as f64 / encoded_total as f64
    };

    let mean_energy_q = mean(stats.iter().map(|s| s.energy_q));
    let mean_energy_k = mean(stats.iter().map(|s| s.energy_k));
    let mean_energy_v = mean(stats.iter().map(|s| s.energy_v));
    let mean_energy_ffn = mean(stats.iter().map(|s| s.energy_ffn));

    eprintln!();
    eprintln!("── encode-rknot summary (input mode) ──");
    eprintln!(
        "source dense .knot bytes:    {:>14} bytes  ({:.2} GiB)",
        dense_input_bytes,
        dense_input_bytes as f64 / (1024.0 * 1024.0 * 1024.0)
    );
    eprintln!(
        "encoded payload bytes:       {:>14} bytes  ({:.2} MiB) over {} layers",
        encoded_total,
        encoded_total as f64 / (1024.0 * 1024.0),
        stats.len(),
    );
    if args.apply_fp48 {
        let bonus = if fp48_total == 0 {
            0.0
        } else {
            encoded_total as f64 / fp48_total as f64
        };
        eprintln!(
            "fp48-wrapped payload bytes:  {:>14} bytes  ({:.2}× bonus over raw payload)",
            fp48_total, bonus
        );
        // Sample the bonus on the synthesized stream of all encoded
        // payload bytes — this is the codebook-friendliness probe the
        // contract asks for in the summary even when the round-trip
        // wrap is on a per-block basis.
        let sample_bonus_ratio = sample_fp48_bonus(stats);
        eprintln!("fp48 bonus ratio (avg):      {:>14.3}", sample_bonus_ratio);
    }
    eprintln!(
        "actual .rknot file:          {:>14} bytes  ({:.2} MiB)",
        rknot_bytes,
        rknot_bytes as f64 / (1024.0 * 1024.0)
    );
    eprintln!("cascade ratio (dense/rknot): {:>14.2}×", cascade_ratio);
    eprintln!(
        "payload ratio (dense/enc):   {:>14.2}×  (excludes header + fp48 wrapping)",
        payload_ratio
    );
    eprintln!(
        "mean standing-energy frac:   Q={:.3} K={:.3} V={:.3} FFN={:.3}",
        mean_energy_q, mean_energy_k, mean_energy_v, mean_energy_ffn
    );
    eprintln!(
        "encode time total:           {:>14.2} ms  (Q {:.1} / K {:.1} / V {:.1} / FFN {:.1})",
        encode_ms, total_timings.q_ms, total_timings.k_ms, total_timings.v_ms, total_timings.ffn_ms,
    );
    eprintln!("write time:                  {:>14.2} ms", write_ms);
    eprintln!("output: {}", output.display());
}

fn mean<I: IntoIterator<Item = f32>>(xs: I) -> f32 {
    let mut sum = 0.0_f32;
    let mut n = 0u32;
    for x in xs {
        sum += x;
        n += 1;
    }
    if n == 0 {
        0.0
    } else {
        sum / n as f32
    }
}

/// Average per-layer fp48 bonus ratio. We don't have the original
/// per-block payloads stashed (we only kept post-pack byte sizes), so
/// derive the average from the (raw_encoded / fp48_packed) byte ratio
/// per layer. Falls back to `fp48_bonus_ratio` on the encoded payload
/// for a single layer if nothing else is available.
fn sample_fp48_bonus(stats: &[LayerStats]) -> f32 {
    if stats.is_empty() {
        return 0.0;
    }
    let mut acc = 0.0_f32;
    let mut n = 0u32;
    for s in stats {
        if s.fp48_bytes > 0 {
            acc += s.encoded_bytes as f32 / s.fp48_bytes as f32;
            n += 1;
        }
    }
    if n == 0 {
        // Last-resort: a synthetic 64-byte zero buffer to keep the
        // summary line populated rather than printing 0.0.
        let probe = vec![0u8; 64];
        return fp48_bonus_ratio(&probe);
    }
    acc / n as f32
}
